@app.route('/analytics/custom', methods=['POST'])
def custom_analytics():
    req_data = request.json
    
    script_code = req_data['script']
    index_name = req_data.get('index', 'analytics')
    
    aggregation_type = req_data.get('agg_type', 'scripted_metric')
    
    if aggregation_type == 'scripted_metric':
        query_body = {
            "size": 0,
            "aggs": {
                "custom_analysis": {
                    "scripted_metric": {
                        "init_script": req_data.get('init_script', 'state.data = []'),
                        "map_script": script_code,
                        "combine_script": req_data.get('combine_script', 'return state.data'),
                        "reduce_script": req_data.get('reduce_script', 'return states')
                    }
                }
            }
        }
    else:
        query_body = {
            "size": 0,
            "aggs": {
                "custom_analysis": {
                    aggregation_type: {
                        "script": {
                            "inline": script_code,
                            "lang": req_data.get('lang', 'painless')
                        }
                    }
                }
            }
        }
    
    result = es.search(index=index_name, body=query_body)
    
    return jsonify(result)

